// Faceted machine-tool knob — finger-grip skirt + shank + domed crown + bore.
// Strategy: fillet each primitive BEFORE fusing, so OCCT's solver works on
// simple edge graphs. Then fuse, then cut the bore, then chamfer the bore rim.
const { BREP } = api;

// Skirt: wide low disc with both outer rims rounded — this is the
// finger-grip BREP showcase. World-Z: bottom rim at z=0, top rim at z=6.
// Use one-sided filters (maxZ for bottom, minZ for top) — symmetric slab
// filters around the same plane confuse OCCT's edge selector on a cylinder.
const skirt = BREP.label(
  BREP.cylinder(20, 6)
    .fillet(1.8, { maxZ: 0.001 })   // bottom outer rim
    .fillet(1.8, { minZ: 5.999 }),  // top outer rim
  'knob',
  { color: '#c0392b' },
);

// Shank: cylindrical column rising above the skirt, with its top rim
// strongly rounded into a domed crown.
const shank = BREP.label(
  BREP.cylinder(14, 18)
    .fillet(6, { minZ: 17.999 })   // domed crown (top rim of unmoved shank)
    .translate([0, 0, 6]),         // park it on the skirt
  'knob',
  { color: '#c0392b' },
);

// Fuse skirt + shank — the rounded body before the bore is cut.
const body = skirt.fuse(shank);

// Bore: 6 mm diameter (r=3), 18 mm deep from the crown — bored down to z=6
// (a press-fit shaft hole into the shank, not all the way through).
// Start slightly above the crown so the boolean produces a clean rim.
const bore = BREP.cylinder(3, 19).translate([0, 0, 6]);

// Subtract the bore, then chamfer the resulting rim (the entry-easing bevel
// every machined shaft hole gets).
const withBore = body.cut(bore);
const knob = withBore.chamfer(0.5, { minZ: 23.5 });

return knob;
